/* =============================================
   BELLA'S KITCHEN - RESTAURANT WEBSITE
   Modern, Mobile-Friendly Design
   ============================================= */

/* Root Variables */
:root {
    --primary-color: #8B3A3A; /* Deep Red */
    --secondary-color: #F5E6D3; /* Cream */
    --accent-color: #C41E3A; /* Italian Red */
    --text-dark: #2C2C2C;
    --text-light: #F5E6D3;
    --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
    --transition: all 0.3s ease;
}

/* =============================================
   GLOBAL STYLES
   ============================================= */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    color: var(--text-dark);
    background-color: #FAFAFA;
    overflow-x: hidden;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

/* =============================================
   TYPOGRAPHY
   ============================================= */

h1, h2, h3, h4, h5, h6 {
    font-family: 'Georgia', serif;
    font-weight: 700;
}

.section-title {
    font-size: 2.5rem;
    color: var(--primary-color);
    text-align: center;
    margin-bottom: 3rem;
    position: relative;
    padding-bottom: 1rem;
}

.section-title::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 80px;
    height: 3px;
    background: linear-gradient(to right, var(--primary-color), var(--accent-color));
    border-radius: 2px;
}

/* =============================================
   NAVIGATION BAR
   ============================================= */

.navbar {
    background-color: var(--primary-color);
    position: sticky;
    top: 0;
    z-index: 100;
    box-shadow: var(--shadow);
}

.nav-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    height: 70px;
}

.nav-brand {
    display: flex;
    align-items: center;
    color: var(--text-light);
    font-size: 1.5rem;
    font-weight: bold;
    gap: 10px;
    cursor: pointer;
}

.nav-brand i {
    font-size: 2rem;
}

.nav-menu {
    display: flex;
    list-style: none;
    gap: 30px;
}

.nav-link {
    color: var(--text-light);
    text-decoration: none;
    font-size: 1rem;
    transition: var(--transition);
    position: relative;
}

.nav-link::after {
    content: '';
    position: absolute;
    width: 0;
    height: 2px;
    bottom: -5px;
    left: 0;
    background-color: var(--secondary-color);
    transition: var(--transition);
}

.nav-link:hover::after {
    width: 100%;
}

.mobile-menu-button {
    display: none;
    flex-direction: column;
    cursor: pointer;
    background: none;
    border: none;
    gap: 5px;
}

.mobile-menu-button span {
    width: 25px;
    height: 3px;
    background-color: var(--text-light);
    border-radius: 3px;
    transition: var(--transition);
}

/* =============================================
   HERO SECTION
   ============================================= */

.hero {
    height: 100vh;
    background: linear-gradient(rgba(139, 58, 58, 0.6), rgba(139, 58, 58, 0.6)), 
                url('https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=1200&fit=crop') center/cover;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
}

.hero-overlay {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(139, 58, 58, 0.5);
}

.hero-content {
    text-align: center;
    color: var(--text-light);
    z-index: 2;
    animation: fadeInUp 1s ease-out;
}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(30px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.hero-title {
    font-size: 4rem;
    margin-bottom: 10px;
    text-shadow: 2px 2px 8px rgba(0, 0, 0, 0.3);
}

.hero-subtitle {
    font-size: 1.5rem;
    margin-bottom: 30px;
    font-weight: 300;
    text-shadow: 1px 1px 4px rgba(0, 0, 0, 0.3);
}

.cta-button {
    background-color: var(--accent-color);
    color: var(--text-light);
    border: none;
    padding: 15px 40px;
    font-size: 1.1rem;
    border-radius: 50px;
    cursor: pointer;
    transition: var(--transition);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.2);
    font-weight: 600;
}

.cta-button:hover {
    background-color: var(--primary-color);
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.3);
}

/* =============================================
   ABOUT SECTION
   ============================================= */

.about {
    padding: 80px 0;
    background-color: #FAFAFA;
}

.about-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 50px;
    align-items: center;
}

.about-text p {
    font-size: 1.1rem;
    line-height: 1.8;
    margin-bottom: 20px;
    color: var(--text-dark);
}

.about-image {
    border-radius: 10px;
    overflow: hidden;
    box-shadow: var(--shadow);
}

.about-image img {
    width: 100%;
    height: auto;
    object-fit: cover;
    transition: var(--transition);
}

.about-image:hover img {
    transform: scale(1.05);
}

/* =============================================
   MENU SECTION
   ============================================= */

.menu {
    padding: 80px 0;
    background: linear-gradient(135deg, #F5E6D3 0%, #FAFAFA 100%);
}

.menu-filters {
    display: flex;
    justify-content: center;
    gap: 15px;
    margin-bottom: 50px;
    flex-wrap: wrap;
}

.filter-button {
    background-color: var(--primary-color);
    color: var(--text-light);
    border: 2px solid var(--primary-color);
    padding: 10px 25px;
    border-radius: 25px;
    cursor: pointer;
    font-size: 1rem;
    transition: var(--transition);
}

.filter-button.active,
.filter-button:hover {
    background-color: var(--accent-color);
    border-color: var(--accent-color);
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 30px;
    margin-bottom: 50px;
}

.menu-item {
    background-color: white;
    border-radius: 10px;
    overflow: hidden;
    box-shadow: var(--shadow);
    transition: var(--transition);
    animation: fadeIn 0.5s ease-out;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.menu-item:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
}

.menu-item-image {
    height: 250px;
    overflow: hidden;
}

.menu-item-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: var(--transition);
}

.menu-item:hover .menu-item-image img {
    transform: scale(1.1);
}

.menu-item-title {
    font-size: 1.3rem;
    color: var(--primary-color);
    padding: 20px 20px 10px;
}

.menu-item-description {
    color: #666;
    font-size: 0.95rem;
    padding: 0 20px;
    line-height: 1.5;
}

.menu-item-price {
    font-size: 1.5rem;
    color: var(--accent-color);
    font-weight: bold;
    padding: 15px 20px;
}

/* =============================================
   GALLERY SECTION
   ============================================= */

.gallery {
    padding: 80px 0;
    background-color: #FAFAFA;
}

.gallery-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: 20px;
}

.gallery-item {
    position: relative;
    height: 300px;
    border-radius: 10px;
    overflow: hidden;
    cursor: pointer;
    box-shadow: var(--shadow);
}

.gallery-item img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: var(--transition);
}

.gallery-overlay {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(139, 58, 58, 0.8);
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: var(--transition);
}

.gallery-overlay h3 {
    color: var(--text-light);
    font-size: 1.8rem;
}

.gallery-item:hover {
    transform: scale(1.05);
}

.gallery-item:hover img {
    transform: scale(1.1);
}

.gallery-item:hover .gallery-overlay {
    opacity: 1;
}

/* =============================================
   HOURS SECTION
   ============================================= */

.hours {
    padding: 80px 0;
    background: linear-gradient(135deg, #F5E6D3 0%, #FAFAFA 100%);
}

.hours-content {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 30px;
}

.hours-card {
    background-color: white;
    padding: 30px;
    border-radius: 10px;
    text-align: center;
    box-shadow: var(--shadow);
    transition: var(--transition);
    border-top: 4px solid var(--primary-color);
}

.hours-card.special {
    border-top-color: var(--accent-color);
    background: linear-gradient(135deg, rgba(139, 58, 58, 0.1), rgba(196, 30, 58, 0.1));
}

.hours-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
}

.hours-card h3 {
    color: var(--primary-color);
    font-size: 1.3rem;
    margin-bottom: 10px;
}

.hours-card p {
    color: #666;
    font-size: 1.1rem;
    font-weight: 600;
}

/* =============================================
   CONTACT SECTION
   ============================================= */

.contact {
    padding: 80px 0;
    background-color: #FAFAFA;
}

.contact-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 50px;
    align-items: start;
}

.info-card {
    background-color: white;
    padding: 25px;
    border-radius: 10px;
    box-shadow: var(--shadow);
    margin-bottom: 20px;
    text-align: center;
    transition: var(--transition);
    border-left: 4px solid var(--primary-color);
}

.info-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
}

.info-card i {
    font-size: 2rem;
    color: var(--accent-color);
    margin-bottom: 10px;
}

.info-card h3 {
    color: var(--primary-color);
    margin-bottom: 10px;
}

.info-card p {
    color: #666;
    line-height: 1.6;
}

/* =============================================
   RESERVATION FORM
   ============================================= */

.reservation-form {
    background-color: white;
    padding: 40px;
    border-radius: 10px;
    box-shadow: var(--shadow);
}

.reservation-form h3 {
    color: var(--primary-color);
    font-size: 1.8rem;
    margin-bottom: 30px;
    text-align: center;
}

.form-group {
    margin-bottom: 20px;
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
}

.form-group input,
.form-group select,
.form-group textarea {
    width: 100%;
    padding: 12px 15px;
    border: 2px solid #E0E0E0;
    border-radius: 5px;
    font-size: 1rem;
    font-family: inherit;
    transition: var(--transition);
    background-color: #F9F9F9;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
    outline: none;
    border-color: var(--primary-color);
    background-color: white;
    box-shadow: 0 0 0 3px rgba(139, 58, 58, 0.1);
}

.form-group input::placeholder,
.form-group textarea::placeholder {
    color: #999;
}

.form-group select {
    cursor: pointer;
}

.form-group textarea {
    resize: vertical;
}

.reservation-form button {
    width: 100%;
    margin-top: 10px;
}

.form-message {
    text-align: center;
    margin-top: 15px;
    font-weight: 600;
    display: none;
}

.form-message.success {
    color: #27ae60;
    display: block;
}

.form-message.error {
    color: #e74c3c;
    display: block;
}

/* =============================================
   FOOTER
   ============================================= */

.footer {
    background-color: var(--primary-color);
    color: var(--text-light);
    padding: 50px 0 20px;
}

.footer-content {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 40px;
    margin-bottom: 30px;
}

.footer-section h4 {
    font-size: 1.3rem;
    margin-bottom: 15px;
    color: var(--secondary-color);
}

.footer-section p {
    line-height: 1.6;
    color: rgba(245, 230, 211, 0.9);
    margin-bottom: 15px;
}

.footer-section ul {
    list-style: none;
}

.footer-section ul li {
    margin-bottom: 10px;
}

.footer-section a {
    color: rgba(245, 230, 211, 0.9);
    text-decoration: none;
    transition: var(--transition);
}

.footer-section a:hover {
    color: var(--secondary-color);
}

.social-links {
    display: flex;
    gap: 15px;
}

.social-links a {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    background-color: rgba(245, 230, 211, 0.2);
    border-radius: 50%;
    font-size: 1.2rem;
    transition: var(--transition);
}

.social-links a:hover {
    background-color: var(--accent-color);
    transform: translateY(-3px);
}

.footer-bottom {
